<template>
  <div class="qr-scanner" :class="rootClass">
    <video
      ref="videoRef"
      class="qr-scanner__video"
      autoplay
      playsinline
      muted
    ></video>

    <slot name="guide" :status="status" :flashing="flashing">
      <GuideOverlay :flashing="flashing" :hint="hintText" />
    </slot>

    <slot name="overlay" :status="status" :stats="stats" :error="error" />

    <div v-if="showStats" class="qr-scanner__stats">
      <span>state: {{ status }}</span>
      <span>frames: {{ stats.framesProcessed }}</span>
      <span>decoded: {{ stats.framesDecoded }}</span>
      <span>bin: {{ stats.lastBinarizerUsed || '—' }}</span>
      <span>last: {{ stats.lastDecodeMs.toFixed(1) }}ms</span>
    </div>

    <div v-if="error" class="qr-scanner__error">
      {{ error.message }}
    </div>
  </div>
</template>

<script lang="ts">
import { defineComponent, ref, computed, onMounted, onBeforeUnmount, watch, type PropType } from 'vue';
import GuideOverlay from './GuideOverlay.vue';
import { useCamera } from '../composables/useCamera';
import { useDecoder } from '../composables/useDecoder';
import type {
  BinarizerStrategy,
  DecoderStats,
  ScannerError,
  ScannerStatus,
} from '../types';

export default defineComponent({
  name: 'QrScanner',
  components: { GuideOverlay },
  props: {
    roiSize: { type: Number, default: 400 },
    debounceMs: { type: Number, default: 2000 },
    autoStart: { type: Boolean, default: true },
    videoConstraints: {
      type: Object as PropType<MediaTrackConstraints>,
      default: () => ({}),
    },
    binarizerStrategy: {
      type: String as PropType<BinarizerStrategy>,
      default: 'auto',
    },
    showStats: { type: Boolean, default: false },
    preferZoom: { type: Number, default: 0 },
  },
  emits: {
    decoded: (_payload: string, _stats: DecoderStats) => true,
    error: (_err: ScannerError) => true,
    status: (_status: ScannerStatus) => true,
  },
  setup(props, { emit }) {
    const videoRef = ref<HTMLVideoElement | null>(null);
    const error = ref<ScannerError | null>(null);
    const flashing = ref(false);
    let flashTimer: ReturnType<typeof setTimeout> | null = null;

    const camera = useCamera({
      videoConstraints: props.videoConstraints,
      preferZoom: props.preferZoom,
      onError: (e) => {
        error.value = e;
        emit('error', e);
      },
    });

    const decoder = useDecoder({
      roiSize: props.roiSize,
      debounceMs: props.debounceMs,
      binarizerStrategy: props.binarizerStrategy,
      onDecoded: (payload, stats) => {
        flashing.value = true;
        if (flashTimer) clearTimeout(flashTimer);
        flashTimer = setTimeout(() => {
          flashing.value = false;
        }, 300);
        emit('decoded', payload, stats);
      },
      onStatusChange: (s) => emit('status', s),
      onError: (e) => {
        error.value = e;
        emit('error', e);
      },
    });

    const status = computed(() => decoder.status.value);
    const stats = computed(() => decoder.stats.value);

    const rootClass = computed(() => ({
      'qr-scanner--running': status.value === 'running',
      'qr-scanner--error': status.value === 'error',
    }));

    const hintText = computed(() => {
      if (status.value === 'error') return error.value?.message ?? '';
      if (status.value === 'running') return '枠に合わせて少し離してください';
      if (status.value === 'initializing') return '初期化中…';
      if (status.value === 'requesting_camera') return 'カメラを要求しています…';
      return '';
    });

    async function start(): Promise<void> {
      if (!videoRef.value) return;
      error.value = null;
      try {
        await camera.start(videoRef.value);
        await decoder.start(videoRef.value);
      } catch (e) {
        const msg = e instanceof Error ? e.message : String(e);
        error.value = { code: 'unknown', message: msg, cause: e };
        emit('error', error.value);
      }
    }

    function stop(): void {
      decoder.stop();
      camera.stop();
      if (flashTimer) {
        clearTimeout(flashTimer);
        flashTimer = null;
      }
      flashing.value = false;
    }

    watch(
      () => props.binarizerStrategy,
      (s) => decoder.setStrategy(s),
    );

    onMounted(() => {
      if (props.autoStart) {
        start();
      }
    });

    onBeforeUnmount(() => {
      stop();
    });

    return {
      videoRef,
      status,
      stats,
      error,
      flashing,
      rootClass,
      hintText,
      start,
      stop,
    };
  },
});
</script>
