export interface RoiExtractor {
  extract(video: HTMLVideoElement, target: Uint8ClampedArray): boolean;
  resize(roiSize: number): void;
  size: number;
}

export function createRoiExtractor(roiSize: number): RoiExtractor {
  let size = roiSize;
  let canvas: HTMLCanvasElement = document.createElement('canvas');
  canvas.width = size;
  canvas.height = size;
  let ctx = canvas.getContext('2d', { willReadFrequently: true }) as
    | CanvasRenderingContext2D
    | null;
  if (!ctx) {
    throw new Error('2D context not available');
  }

  function extract(video: HTMLVideoElement, target: Uint8ClampedArray): boolean {
    const vw = video.videoWidth;
    const vh = video.videoHeight;
    if (vw === 0 || vh === 0) {
      return false;
    }
    const cropSide = Math.min(vw, vh, size * 4);
    const sx = Math.floor((vw - cropSide) / 2);
    const sy = Math.floor((vh - cropSide) / 2);

    ctx!.drawImage(video, sx, sy, cropSide, cropSide, 0, 0, size, size);
    const imageData = ctx!.getImageData(0, 0, size, size);
    target.set(imageData.data);
    return true;
  }

  function resize(newSize: number): void {
    if (newSize === size) {
      return;
    }
    size = newSize;
    canvas = document.createElement('canvas');
    canvas.width = size;
    canvas.height = size;
    ctx = canvas.getContext('2d', { willReadFrequently: true });
    if (!ctx) {
      throw new Error('2D context not available');
    }
  }

  return {
    extract,
    resize,
    get size() {
      return size;
    },
  };
}
