import { ref, type Ref } from 'vue';
import { DecoderClient } from '../decoder/client';
import { createRoiExtractor, type RoiExtractor } from './useRoi';
import { createPayloadDebouncer } from './useDebounce';
import type {
  BinarizerStrategy,
  DecoderStats,
  ScannerError,
  ScannerStatus,
} from '../types';

export interface UseDecoderOptions {
  roiSize: number;
  debounceMs: number;
  binarizerStrategy: BinarizerStrategy;
  onDecoded: (payload: string, stats: DecoderStats) => void;
  onStats?: (stats: DecoderStats) => void;
  onStatusChange?: (status: ScannerStatus) => void;
  onError?: (err: ScannerError) => void;
}

interface FrameLoopHandle {
  cancel(): void;
}

function startFrameLoop(video: HTMLVideoElement, callback: () => void): FrameLoopHandle {
  const anyVideo = video as HTMLVideoElement & {
    requestVideoFrameCallback?: (
      cb: (now: number, metadata: unknown) => void,
    ) => number;
    cancelVideoFrameCallback?: (handle: number) => void;
  };

  if (typeof anyVideo.requestVideoFrameCallback === 'function') {
    let handle = 0;
    let cancelled = false;
    const tick = () => {
      if (cancelled) return;
      callback();
      handle = anyVideo.requestVideoFrameCallback!(tick);
    };
    handle = anyVideo.requestVideoFrameCallback(tick);
    return {
      cancel() {
        cancelled = true;
        if (anyVideo.cancelVideoFrameCallback && handle) {
          anyVideo.cancelVideoFrameCallback(handle);
        }
      },
    };
  }

  let cancelled = false;
  let timer: ReturnType<typeof setTimeout> | null = null;
  const intervalMs = 1000 / 30;
  const tick = () => {
    if (cancelled) return;
    callback();
    timer = setTimeout(tick, intervalMs);
  };
  timer = setTimeout(tick, intervalMs);
  return {
    cancel() {
      cancelled = true;
      if (timer) {
        clearTimeout(timer);
      }
    },
  };
}

export interface UseDecoderReturn {
  status: Ref<ScannerStatus>;
  stats: Ref<DecoderStats>;
  start: (video: HTMLVideoElement) => Promise<void>;
  stop: () => void;
  setStrategy: (strategy: BinarizerStrategy) => void;
}

export function useDecoder(opts: UseDecoderOptions): UseDecoderReturn {
  const status = ref<ScannerStatus>('idle');
  const stats = ref<DecoderStats>({
    framesProcessed: 0,
    framesDecoded: 0,
    lastBinarizerUsed: '',
    lastDecodeMs: 0,
  });

  let client: DecoderClient | null = null;
  let extractor: RoiExtractor | null = null;
  let loop: FrameLoopHandle | null = null;
  const debouncer = createPayloadDebouncer(opts.debounceMs);

  function setStatus(next: ScannerStatus) {
    if (status.value !== next) {
      status.value = next;
      opts.onStatusChange?.(next);
    }
  }

  async function start(video: HTMLVideoElement): Promise<void> {
    if (client) return;
    setStatus('initializing');

    extractor = createRoiExtractor(opts.roiSize);
    client = new DecoderClient({
      width: opts.roiSize,
      height: opts.roiSize,
      poolSize: 3,
      onDecoded: (payload, s) => {
        stats.value = s;
        opts.onStats?.(s);
        if (debouncer.accept(payload)) {
          opts.onDecoded(payload, s);
        }
      },
      onFrameDone: (s) => {
        stats.value = s;
        opts.onStats?.(s);
      },
      onError: (e) => {
        setStatus('error');
        opts.onError?.(e);
      },
    });

    try {
      await client.init();
    } catch (e) {
      setStatus('error');
      opts.onError?.({
        code: 'wasm_init_failed',
        message: e instanceof Error ? e.message : String(e),
        cause: e,
      });
      return;
    }

    if (opts.binarizerStrategy && opts.binarizerStrategy !== 'auto') {
      client.setStrategy(opts.binarizerStrategy);
    }

    setStatus('running');

    loop = startFrameLoop(video, () => {
      if (!client || !extractor) return;
      if (client.pendingFrames() >= 2) return;
      const buf = client.acquireBuffer();
      if (!buf) return;
      const ok = extractor.extract(video, buf);
      if (!ok) {
        client.acquireBuffer();
        return;
      }
      client.sendFrame(buf);
    });
  }

  function stop(): void {
    loop?.cancel();
    loop = null;
    client?.dispose();
    client = null;
    extractor = null;
    debouncer.reset();
    setStatus('idle');
  }

  function setStrategy(strategy: BinarizerStrategy): void {
    if (client) {
      client.setStrategy(strategy);
    }
  }

  return { status, stats, start, stop, setStrategy };
}
